const entry = $input.first().json;

// Estructura REAL que entrega el trigger de n8n
const from = entry.messages?.[0]?.from || '';
const phoneNumberId = entry.metadata?.phone_number_id || '';
const contactName = entry.contacts?.[0]?.profile?.name || '';

const msg = entry.messages?.[0];
const msgType = msg?.type || 'text';

let textContent = '';
let mediaId = '';
let mediaUrl = '';

if (msgType === 'text') {
  textContent = msg?.text?.body || '';
} else if (msgType === 'image') {
  mediaId = msg?.image?.id || '';
  mediaUrl = msg?.image?.url || '';          // ← YA viene la URL directa!
  textContent = msg?.image?.caption || '[IMAGEN_ENVIADA]';
} else if (msgType === 'document') {
  mediaId = msg?.document?.id || '';
  textContent = '[DOCUMENTO_ENVIADO]';
}

return [{
  json: {
    from,
    phoneNumberId,
    contactName,    // ← BONUS: nombre del contacto de WhatsApp
    msgType,
    textContent,
    mediaId,
    mediaUrl,       // ← URL directa disponible
    hasImage: msgType === 'image'
  }
}];

// Convertir imagen binaria a base64 para enviarsela a OpenAI Vision
const binaryData = $input.first().binary?.data;

if (!binaryData) {
  throw new Error('No se recibió imagen binaria');
}

// n8n guarda el binario, lo pasamos como referencia
const base64Image = binaryData.data; // Ya viene en base64 desde n8n
const mimeType = binaryData.mimeType || 'image/jpeg';

// Recuperar datos del mensaje original (de 2 nodos atrás)
// Los pasamos como contexto para el agente
return [{
  json: {
    base64Image,
    mimeType,
    imageDataUrl: `data:${mimeType};base64,${base64Image}`
  },
  binary: $input.first().binary
}];

const binary = $input.first().binary?.data;
const json = $input.first().json;

return [{
  json: {
    ...json,
    // Guardar el binario como base64 en el JSON para no perderlo
    imagenBase64: binary?.data || '',
    imagenMimeType: binary?.mimeType || 'image/jpeg',
    imagenFileName: binary?.fileName || 'colilla.jpg'
  }
  // NO pasar binary aquí, el agente no lo necesita
}];

// Tomar el binario DIRECTO del nodo que descargó la imagen
const binary = $('1. Obtener URL de Imagen1').first().binary?.data;

if (!binary) {
  throw new Error('No se encontró binario en el nodo de descarga');
}

return [{
  json: $input.first().json,
  binary: {
    data: binary  // binario original sin tocar
  }
}];

// Tomar el binario DIRECTO del nodo que descargó la imagen
const binary = $('1. Obtener URL de Imagen1').first().binary?.data;

if (!binary) {
  throw new Error('No se encontró binario en el nodo de descarga');
}

return [{
  json: $input.first().json,
  binary: {
    data: binary  // binario original sin tocar
  }
}];

let output = $input.first().json.output || "";

// 1. Limpiar bloques de código Markdown ```json ... ```
output = output.replace(/```json/g, "").replace(/```/g, "").trim();

// 2. Extraer el JSON real
let jsonMatch = output.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  return [{ 
    json: { 
      extracted_cedula: null, 
      extracted_nombre: null, 
      tipo_documento_detectado: null,
      extracted_id_tra: null,
      extracted_identificacion: null,
      extracted_valor: null,
      error: "No se encontró JSON en la respuesta del agente" 
    } 
  }];
}

try {
  let data = JSON.parse(jsonMatch[0]);

  return [{
    json: {
      extracted_cedula:          data.extracted_cedula         || null,
      extracted_nombre:          data.extracted_nombre         || null,
      tipo_documento_detectado:  data.tipo_documento_detectado || null,
      extracted_id_tra:          data.extracted_id_tra         || null,
      extracted_identificacion:  data.extracted_identificacion || null,
      extracted_valor:           data.extracted_valor          || null
    }
  }];

} catch (e) {
  return [{ 
    json: { 
      extracted_cedula: null, 
      extracted_nombre: null, 
      tipo_documento_detectado: null,
      extracted_id_tra: null,
      extracted_identificacion: null,
      extracted_valor: null,
      error: "JSON inválido: " + e.message 
    } 
  }];
}

